/* 事件总线接口定义 */
typedef void (*event_handler_t)(
    const void *payload);

typedef struct {
    uint8_t id;
    const char *name;
} event_id_t;

typedef struct {
    event_handler_t handlers[16];
    uint8_t count;
} event_bus_t;

/* 发布事件 */
static inline void event_publish(
    event_bus_t *bus,
    const void *payload)
{
    for (int i = 0; i < bus->count; i++) {
        if (bus->handlers[i]) {
            bus->handlers[i](payload);
        }
    }
}

/* 注册回调 */
static inline void event_subscribe(
    event_bus_t *bus,
    event_handler_t h)
{
    if (bus->count < 16) {
        bus->handlers[bus->count++] = h;
    }
}

/* 使用示例 */
static void adc_convert_done(
    const void *payload)
{
    const sample_t *s = payload;
    pid_update(&pid_ctx, s->value);
}

static event_bus_t system_bus;

void system_init(void)
{
    event_subscribe(&system_bus,
                    adc_convert_done);
}

