/* 改造后：传感器只发布事件 */

/* sensor.c */
extern void event_publish(
    event_bus_t *bus,
    const void *payload);

static const event_id_t EVT_ADC_READY =
    { .id = 42, .name = "ADC_READY" };

void sensor_task(void)
{
    sample_t sample;
    while (1) {
        sample.value = adc_read();
        event_publish(&system_bus,
                      &sample);
        vTaskDelay(pdMS_TO_TICKS(10));
    }
}

/* control.c */
static void on_adc_ready(
    const void *payload)
{
    const sample_t *s = payload;
    pid_update(&pid_ctx, s->value);
}

void control_init(void)
{
    event_subscribe(&system_bus,
                    on_adc_ready);
}
